<?php declare(strict_types=1);namespace App\Students;class Student extends Person{public function __construct(string $name,int $age,private string $studentID){parent::__construct($name,$age);if(trim($studentID)==='')throw new \InvalidArgumentException('Mã sinh viên không được trống.');}public function data():array{return ['name'=>$this->name,'age'=>$this->age,'studentID'=>$this->studentID];}}
